   199→internal sealed class MockHttpTestServer : IDisposable
   200→{
   201→    private readonly HttpListener _listener;
   202→    private readonly CancellationTokenSource _cancellationTokenSource;
   203→    private readonly TaskCompletionSource _ready;
   204→    public string Endpoint { get; }
   205→
   206→    public MockHttpTestServer()
   207→    {
   208→        var port = GetAvailablePort();
   209→        Endpoint = $"http://127.0.0.1:{port}";
   210→
   211→        _listener = new HttpListener();
   212→        _listener.Prefixes.Add($"{Endpoint}/");
   213→        _listener.Start();
   214→
   215→        _cancellationTokenSource = new CancellationTokenSource();
   216→        _ready = new TaskCompletionSource();
   217→
   218→        _ = Task.Run(async () =>
   219→        {
   220→            try
   221→            {
   222→                _ready.SetResult();
   223→
   224→                while (_listener.IsListening && !_cancellationTokenSource.Token.IsCancellationRequested)
   225→                {
   226→                    var context = await _listener.GetContextAsync();
   227→                    if (context.Request.Url?.AbsolutePath == "/mcp")
   228→                    {
   229→                        context.Response.StatusCode = 404;
   230→                    }
   231→                    else
   232→                    {
   233→                        context.Response.StatusCode = 400;
   234→                    }
   235→                    context.Response.Close();
   236→                }
   237→            }
   238→            catch (Exception ex) when (ex is ObjectDisposedException or HttpListenerException)
   239→            {
   240→                // expected when listener is disposed or stopped.
   241→                if (!_ready.Task.IsCompleted)
   242→                {
   243→                    _ready.SetException(ex);
   244→                }
   245→            }
   246→        }, _cancellationTokenSource.Token);
   247→
   248→        _ready.Task.Wait(TimeSpan.FromSeconds(10));
   249→    }
   250→
   251→    private static int GetAvailablePort()
   252→    {
   253→        using var tempListener = new TcpListener(IPAddress.Loopback, 0);
   254→        tempListener.Start();
   255→        var port = ((IPEndPoint)tempListener.LocalEndpoint).Port;
   256→        tempListener.Stop();
   257→        return port;
   258→    }
   259→
   260→    public void Dispose()
   261→    {
   262→        _cancellationTokenSource.Cancel();
   263→        _listener.Stop();
   264→        _listener.Close();
   265→        _cancellationTokenSource.Dispose();
   266→    }
   267→}
