using System;
using System.Threading.Tasks;
using AzureMcp.Areas.Server.Commands.Discovery;
using AzureMcp.Areas.Server.Models;
using AzureMcp.Areas.Server.Options;
using ModelContextProtocol.Client;
using Xunit;

namespace AzureMcp.Tests;

/// <summary>
/// Test to verify SSE support has been removed
/// </summary>
public class SseRemovalTests
{
    [Fact]
    public void TransportTypes_ShouldNotHaveSseConstant()
    {
        // This test verifies that TransportTypes.Sse constant no longer exists
        var type = typeof(TransportTypes);
        var sseField = type.GetField("Sse");
        Assert.Null(sseField);
    }

    [Fact]
    public void TransportTypes_ShouldOnlyHaveStdIo()
    {
        // Verify only stdio transport is available
        var type = typeof(TransportTypes);
        var stdioField = type.GetField("StdIo");
        Assert.NotNull(stdioField);
        Assert.Equal("stdio", stdioField.GetValue(null));
    }

    [Fact]
    public void RegistryServerInfo_ShouldNotHaveUrlProperty()
    {
        // This test verifies that RegistryServerInfo.Url property no longer exists
        var type = typeof(RegistryServerInfo);
        var urlProperty = type.GetProperty("Url");
        Assert.Null(urlProperty);
    }

    [Fact]
    public async Task RegistryServerProvider_WithStdioType_ShouldWork()
    {
        // Arrange
        string testId = "stdioProvider";
        var serverInfo = new RegistryServerInfo
        {
            Description = "Test Stdio Provider",
            Type = "stdio",
            Command = "echo",
            Args = new System.Collections.Generic.List<string> { "hello world" }
        };
        var provider = new RegistryServerProvider(testId, serverInfo);

        // Act & Assert - Should not throw InvalidOperationException about URL
        var exception = await Record.ExceptionAsync(() => provider.CreateClientAsync(new McpClientOptions()));

        // We expect some exception but not about missing URL since URL should no longer be supported
        Assert.NotNull(exception);
        Assert.DoesNotContain("url", exception.Message.ToLower());
    }

    [Fact]
    public async Task RegistryServerProvider_WithoutUrlOrType_ShouldThrowInvalidOperationException()
    {
        // Arrange
        string testId = "invalidProvider";
        var serverInfo = new RegistryServerInfo
        {
            Description = "Invalid Provider - No Transport"
        };
        var provider = new RegistryServerProvider(testId, serverInfo);

        // Act & Assert
        var exception = await Assert.ThrowsAsync<InvalidOperationException>(
            () => provider.CreateClientAsync(new McpClientOptions()));

        // The error message should mention type but not URL
        Assert.Contains("type", exception.Message.ToLower());
        Assert.DoesNotContain("url", exception.Message.ToLower());
    }

    [Fact]
    public void ServiceStartOptions_WithSseTransport_ShouldStillCompile()
    {
        // This test verifies ServiceStartOptions can still be created
        // but SSE transport should no longer be valid
        var options = new ServiceStartOptions
        {
            Transport = "sse", // This should be invalid after removal
            Port = 5008
        };

        Assert.NotNull(options);
        Assert.Equal("sse", options.Transport);
    }
}

